#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int heights[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &heights[i]);
    }
    int maxJumps[n];
    for (int i = 0; i < n; i++) {
        maxJumps[i] = 0;
    }
    for (int i = 0; i < n; i++) {
        int left = 0;
        int right = 0;
        for (int j = i - 1; j >= 0; j--) {
            if (heights[j] < heights[i]) {
                left++;
            }
        }
        for (int j = i + 1; j < n; j++) {
            if (heights[j] < heights[i]) {
                right++;
            }
        }
        maxJumps[i] = (left > 0 || right > 0) ? 1 + (left > right ? left : right) : 0;
    }
    for (int i = 0; i < n; i++) {
        printf("%d ", maxJumps[i]);
    }
    return 0;
}

